module div_8bit (
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] quotient_reg, remainder_reg;
    reg [3:0] shift_count;
    reg [1:0] state;

    localparam IDLE = 2'b00;
    localparam DIVIDE = 2'b01;
    localparam DONE = 2'b10;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            res_valid <= 0;
            shift_count <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (opn_valid) begin
                        dividend_reg <= dividend;
                        divisor_reg <= divisor;
                        quotient_reg <= 0;
                        remainder_reg <= 0;
                        shift_count <= 0;
                        state <= DIVIDE;
                    end
                end
                DIVIDE: begin
                    if (shift_count < 8) begin
                        {remainder_reg, dividend_reg} <= {remainder_reg, dividend_reg} << 1;
                        remainder_reg <= remainder_reg - divisor_reg;
                        if (remainder_reg < 0) begin
                            remainder_reg <= remainder_reg + divisor_reg;
                        end else begin
                            quotient_reg[7 - shift_count] <= 1;
                        end
                        shift_count <= shift_count + 1;
                    end else begin
                        if (sign && (dividend[7] ^ divisor[7])) begin
                            quotient_reg <= -quotient_reg;
                        end
                        result <= {remainder_reg, quotient_reg};
                        res_valid <= 1;
                        state <= DONE;
                    end
                end
                DONE: begin
                    if (res_ready) begin
                        res_valid <= 0;
                        state <= IDLE;
                    end
                end
            endcase
        end
    end

endmodule
